headers = [
  'ID','Scenario Name','Region','Flavor / Setup',
  'Option 1 Text','Result 1','HP Change 1','Summary 1',
  'Option 2 Text','Result 2','HP Change 2','Summary 2',
  'Option 3 Text','Result 3','HP Change 3','Summary 3',
  'Option 4 Text','Result 4','HP Change 4','Summary 4',
]
