for ci, (h, w) in enumerate(zip(headers, col_widths), 1):
    cell = ws.cell(row=1, column=ci, value=h)
    cell.font = header_font
    cell.fill = header_fill
    cell.alignment = center
    ws.column_dimensions[get_column_letter(ci)].width = w

def parse_result(r):
    if r == 'treasure':   return 'Draw Treasure Card', ''
    if r == 'territory':  return 'Draw Territory Card', ''
    m = re.match(r'damage_(\d+)', r)
    if m: return 'Lose HP', f'-{m.group(1)}'
    m = re.match(r'heal_(\d+)', r)
    if m: return 'Gain HP', f'+{m.group(1)}'
    return r, ''

region_map = {'The Valley Meadows':'meadow','The Mountain Forests':'forest','The Misty Islands':'misty','The Volcan Mountains':'volcan'}
prefix_map = {'meadow':'M','forest':'F','misty':'I','volcan':'V'}
counters   = {'meadow':0,'forest':0,'misty':0,'volcan':0}

all_scenarios = meadow + forest + misty + volcan
row = 2
for sc in all_scenarios:
    name, region, flavor = sc[0], sc[1], sc[2]
    reg_key = region_map.get(region, 'meadow')
    counters[reg_key] += 1
    sid = f"{prefix_map[reg_key]}{counters[reg_key]:02d}"

    opts = sc[3:]  # 16 values: text1,result1,summary1, text2,...
    row_data = [sid, name, region, flavor]
    for i in range(4):
        ot = opts[i*3]
        rt, hp = parse_result(opts[i*3+1])
        sm = opts[i*3+2]
        row_data += [ot, rt, hp, sm]

    for ci, val in enumerate(row_data, 1):
        cell = ws.cell(row=row, column=ci, value=val)
        cell.alignment = wrap
        if row % 2 == 0:
            cell.fill = alt_fill
    ws.row_dimensions[row].height = 80
    row += 1

ws.freeze_panes = 'A2'
ws.auto_filter.ref = f'A1:{get_column_letter(len(headers))}1'

